Rule.Source:
  List filesList = application.getAttributeValue("mergeFilesList");
  String mergedFile = application.getAttributeValue("file");

  FileWriter fw = null;
  FileReader fileReader = null;
  BufferedReader br = null;


  if (filesList != null && mergedFile != null && !filesList.contains(mergedFile)) {
    try {
      boolean addHeader = true;
      fw = new FileWriter(mergedFile);
      for(String eachFile : filesList) {
        try {
          fileReader = new FileReader(eachFile);    
          br = new BufferedReader(fileReader);
          if (addHeader) {
            String header = br.readLine();
            if (header != null) {
              fw.write(header);
              fw.write("\n");
            }
            addHeader = false;
          } else {
            //skip header 
            br.readLine();
          }
          String line = br.readLine();
          while(line != null){
            fw.write(line);
            fw.write("\n");
            line = br.readLine();
          }
          br.close();
          fileReader.close();
        } catch (FileNotFoundException fnfe) {
					log.error("Exception in merging files in pre-iterate rule "+ fnfe.getMessage());
        }
      }
      fw.close();
    } catch (IOException ioe) {
      log.error("Exception in merging files in pre-iterate rule "+ ioe.getMessage());
    } finally {
      try {
        if(br!=null)
          br.close();
        if(fileReader!=null)
          fileReader.close();
        if(fw!=null)
          fw.close();
      } catch (IOException ioe2) {
        log.error("Exception in closing file connections "+ ioe2.getMessage());
      }
    }
  }


  return null;
